patch:
diff --git a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
index bd225bcc0635..96d985fb951e 100644
--- a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
+++ b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
@@ -1446,6 +1446,15 @@ static ScalarizationResult canScalarizeAccess(VectorType *VecTy, Value *Idx,
   }

   unsigned IntWidth = Idx->getType()->getScalarSizeInBits();
+  // If the index type cannot represent all in-bounds values [0, NumElements),
+  // then any possible index value is necessarily in-bounds. Avoid constructing
+  // APInt with a value that does not fit the index bit-width.
+  // If NumElements does not fit in the index type width (i.e. NumElements >= 2^IntWidth),
+  // avoid constructing APInt with an out-of-range value. Be conservative and
+  // do not allow scalarization to proceed.
+  if (NumElements >= (IntWidth >= 64 ? std::numeric_limits<uint64_t>::max() : (uint64_t(1) << IntWidth)))
+    return ScalarizationResult::unsafe();
+
   APInt Zero(IntWidth, 0);
   APInt MaxElts(IntWidth, NumElements);
   ConstantRange ValidIndices(Zero, MaxElts);

